javascript.findReferences:
function findLawReferences(lawText, lawName) {
  const references = [];
  const baseUrl = 'https://law.go.kr/법령/';

  // 1. 대통령령 패턴
  const presidentialRegex = /대통령령(으로|이)\s*(정하는|정한다|정하는\s*바)/g;
  let match;

  while ((match = presidentialRegex.exec(lawText)) !== null) {
    references.push({
      text: match[0],
      url: `${baseUrl}${encodeURIComponent(lawName)}%20시행령`,
      type: '시행령',
      lawName: `${lawName} 시행령`,
      startIndex: match.index,
      endIndex: match.index + match[0].length
    });
  }

  // 2. 총리령 패턴
  const primeMinisterRegex = /총리령(으로|이)\s*(정하는|정한다|정하는\s*바)/g;

  while ((match = primeMinisterRegex.exec(lawText)) !== null) {
    references.push({
      text: match[0],
      url: `${baseUrl}${encodeURIComponent(lawName)}%20시행규칙`,
      type: '시행규칙',
      lawName: `${lawName} 시행규칙`,
      startIndex: match.index,
      endIndex: match.index + match[0].length
    });
  }

  // 3. 부령 패턴
  const ministryRegex = /([\w가-힣]+부)령(으로|이)\s*(정하는|정한다|정하는\s*바)/g;

  while ((match = ministryRegex.exec(lawText)) !== null) {
    const ministryName = match[1];
    references.push({
      text: match[0],
      url: `${baseUrl}${encodeURIComponent(lawName)}%20시행규칙`,
      type: '시행규칙',
      ministry: ministryName,
      lawName: `${lawName} 시행규칙`,
      startIndex: match.index,
      endIndex: match.index + match[0].length
    });
  }

  // 4. 청장/부장관 패턴 (고시/예규)
  const agencyHeadRegex = /([\w가-힣]+청장|[\w가-힣]+부장관|[\w가-힣]+장관)(이|가)\s*(정하는|정한다|고시하는)/g;

  while ((match = agencyHeadRegex.exec(lawText)) !== null) {
    const agencyHead = match[1];
    references.push({
      text: match[0],
      url: null, // API 조회 필요
      type: '고시/예규',
      agencyHead: agencyHead,
      lawName: lawName,
      startIndex: match.index,
      endIndex: match.index + match[0].length,
      needsApiLookup: true,
      apiQuery: lawName
    });
  }

  // 5. 명시적 시행령/시행규칙 참조
  const explicitRegex = /(이\s*법\s*)?(시행령|시행규칙)(\s*제\s*(\d+)\s*조)?/g;

  while ((match = explicitRegex.exec(lawText)) !== null) {
    const refType = match[2];
    const article = match[4];

    let url = `${baseUrl}${encodeURIComponent(lawName)}%20${refType}`;
    if (article) {
      url += `/제${article}조`;
    }

    references.push({
      text: match[0],
      url: url,
      type: refType,
      article: article || null,
      lawName: `${lawName} ${refType}`,
      startIndex: match.index,
      endIndex: match.index + match[0].length
    });
  }

  return references;
}

javascript.fetchHierarchy:
async function fetchLawHierarchy(lawName, apiKey) {
  const apiUrl = 'http://www.law.go.kr/DRF/lawSearch.do';
  const params = new URLSearchParams({
    OC: apiKey,
    target: 'lsStmd',
    type: 'JSON',
    query: lawName,
    display: 100
  });

  try {
    const response = await fetch(`${apiUrl}?${params}`);
    const data = await response.json();

    if (data.resultCode === '00') {
      return {
        success: true,
        laws: data.law || [],
        totalCount: data.totalCnt
      };
    } else {
      return {
        success: false,
        error: data.resultMsg
      };
    }
  } catch (error) {
    return {
      success: false,
      error: error.message
    };
  }
}

javascript.applyLinks:
function applyLawLinks(lawText, references) {
  references.sort((a, b) => b.startIndex - a.startIndex);

  let result = lawText;

  references.forEach(ref => {
    const before = result.substring(0, ref.startIndex);
    const after = result.substring(ref.endIndex);

    let link;
    if (ref.needsApiLookup) {
      // API 조회가 필요한 경우 (고시/예규)
      link = `<a href="#" 
                 class="law-reference law-needs-lookup" 
                 data-law-name="${ref.lawName}"
                 data-law-type="${ref.type}"
                 data-agency-head="${ref.agencyHead}"
                 data-api-query="${ref.apiQuery}"
                 onclick="openLawModalWithApiLookup(event, this)"
                 style="color: #0066cc; text-decoration: underline; cursor: pointer;">
                 ${ref.text}
               </a>`;
    } else {
      // 직접 URL이 있는 경우
      link = `<a href="${ref.url}" 
                 class="law-reference" 
                 data-law-name="${ref.lawName}"
                 data-law-type="${ref.type}"
                 data-law-url="${ref.url}"
                 onclick="openLawModal(event, this)"
                 style="color: #0066cc; text-decoration: underline; cursor: pointer;">
                 ${ref.text}
               </a>`;
    }

    result = before + link + after;
  });

  return result;
}

